var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"우, 우왓…!? 깜짝이야……!","JPN":"う、うわっ……！？　びっくりした……！","ENG":"W-whoa...?! You scared me...!","TWN":"嗚，嗚哇…！？嚇死我……！"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"코치! 뜬금없이 실내에서 폭죽 같은 걸 터트리면 어떻게 해요……!?","JPN":"コーチ！　室内でいきなりクラッカーを鳴らしたりしたら、心臓に悪いじゃないですか！","ENG":"Coach! Who sets off fireworks indoors out of nowhere like that...?!","TWN":"教練！你怎麼可以突然在室內放煙火……！？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"게다가 이 화려한 장식이랑… 잔뜩 쌓여 있는 마카롱은 대체……!?","JPN":"それに、この派手な飾り……山盛りのマカロンはいったい……！？","ENG":"And what's with all these fancy decorations... and this mountain of macarons...?!","TWN":"然後這些華麗的裝飾…還有堆得滿滿的馬卡龍是怎樣……！？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"네? 리그 우승 축하한다고요?","JPN":"え？　リーグ優勝おめでとう……？","ENG":"Huh? You're congratulating me on winning the League?","TWN":"什麼？因為要慶祝聯賽奪冠？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"뭐, 뭐예요, 그게…!? 대체 그게 언젯적 이야기예요……!?","JPN":"それっていつの話ですか！？　もう……！","ENG":"W-what...?! That was forever ago...!","TWN":"什，什麼……！？那都多久以前的事啦……！？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"물론, 그 뒤로… 이런저런 사건들 때문에 어정쩡하게 넘어가긴 했지만…….","JPN":"まあ、その後……いろんな事件があったせいで、有耶無耶になったのは事実ですけど……","ENG":"Sure, we kind of just brushed it aside because of everything that happened afterward, but still...","TWN":"確實…那時候因為發生太多事，都沒有好好慶祝……"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그래도 이건 축하가 너무 늦었잖아요! 코치는 바보야!","JPN":"だとしても、今更お祝いなんて遅すぎです！　コーチのバカ！","ENG":"Even so, the celebration's way too late! Coach, you dummy!","TWN":"但現在未免也太晚！教練你這個笨蛋！"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"네? 저랑 단둘이 있을 때, 따로 축하해 주고 싶었다고요?","JPN":"え？　私と二人きりのときに、ちゃんとお祝いしてあげたかった？","ENG":"Huh? You wanted to celebrate with just the two of us?","TWN":"什麼？你想趁只有我們二個人的時候慶祝嗎？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그, 그게 무슨……?","JPN":"そ、それはどういう……？","ENG":"W-what does that even...?","TWN":"這，這是什麼意思……？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"하, 하하…….","JPN":"は、はは……","ENG":"Ha, haha...","TWN":"哈，哈哈……"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"하여간 이상한 사람이라니까요, 코치는…….","JPN":"本当に変な人ですよね、コーチって……","ENG":"Seriously, you're so weird sometimes, Coach...","TWN":"教練果然是怪人……"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그래도 고마워요, 코치.","JPN":"でも、ありがとうございます。コーチ。 ","ENG":"But thanks, Coach. ","TWN":"不過，謝謝你，教練。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"제가 이곳에 남을 수 있는 이유는 전부 코치 덕분인걸요.","JPN":"私がここにいられるのは、全部コーチのおかげですから。","ENG":"I'm only able to stay here because of you.","TWN":"我能夠留在這裡，全都是因為你。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"코치가 아니었다면, 모두와 만날 수 없었겠죠.","JPN":"コーチのおかげで、みんなと出会えました。","ENG":"If it weren't for you, I never would've met everyone.","TWN":"如果沒有教練，就不會遇見大家。"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그리고 코치가 없었다면 저는……","JPN":"それに、コーチがいなかったら私は……","ENG":"And if you weren't here, I...","TWN":"要是沒有教練，我……"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"읏!?","JPN":"っ！？","ENG":"Ngh...?!","TWN":"唔！？"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"으으……!","JPN":"うう……！","ENG":"Ugh...!","TWN":"嗚嗚……！"},"stage":{"bg":"LIFETIME","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};